<START_OF_CONTENT(as it is including trailing newlines)>1→// Selector card (BLOCKER #2/#5/#6/#10 fix): license-plate mini-search + 3-step cascade
2→// + Buscar CTA. The Buscar CTA is ALWAYS bright blue #0068D7 (hover #0074F1),
3→// matching the live site — even when no selection is made. Height: 48px, radius: 1.86px.
4→import { useState } from 'react';
5→import { MAKES } from '../data/makes.js';
6→import { MODELS } from '../data/models.js';
7→import { ENGINES } from '../data/engines.js';
8→import { useSelection } from '../state/SelectionContext.jsx';
9→import StepDropdown from './StepDropdown.jsx';
10→
11→export default function SelectorCard() {
12→  const { selection, setMake, setModel, setEngine, reset } = useSelection();
13→  const [plate, setPlate] = useState('');
14→  const [ctaHover, setCtaHover] = useState(false);
15→
16→  const makeOptions = MAKES;
17→  const makeId = MAKES.find((m) => m.name === selection.make)?.id;
18→  const modelOptions = makeId ? MODELS[makeId] || [] : [];
19→  const modelId = makeId ? MODELS[makeId]?.find((m) => m.name === selection.model)?.id : null;
20→  const engineOptions = modelId ? ENGINES[modelId] || [] : [];
21→
22→  const canSearch = !!(selection.make && selection.model && selection.engine);
23→  const canSearchPlate = plate.trim().length >= 4;
24→
25→  // CTA color: always blue; hover variant is only a visual change (not a disabled state).
26→  const ctaBg = ctaHover ? '#0074F1' : '#0068D7';
27→
28→  return (
29→    <div
30→      className="w-full max-w-[520px] p-6"
31→      style={{ backgroundColor: '#F9FAFB', borderRadius: '5px' }}
32→    >
33→      {/* License-plate mini-search */}
34→      <div className="mb-6">
35→        <div className="text-[14px] font-semibold text-body-text mb-2">Buscar modelo de coche por matrícula</div>
36→        <div className="flex items-stretch gap-0">
37→          <div
38→            className="flex items-center justify-center flex-shrink-0"
39→            style={{ width: 48, height: 48, backgroundColor: '#003AAB', color: '#FFFFFF', borderRadius: '2px 0 0 2px' }}
40→            aria-label="España"
41→          >
42→            <span className="text-[14px] font-bold">E</span>
43→          </div>
44→          <input
45→            type="text"
46→            value={plate}
47→            onChange={(e) => setPlate(e.target.value)}
48→            placeholder="1234-ABC"
49→            maxLength={12}
50→            aria-label="Matrícula"
51→            className="flex-1 outline-none text-[14px] text-body-text"
52→            style={{
53→              backgroundColor: '#FFFFFF',
54→              border: '1px solid #C4D0D8',
55→              borderLeft: 'none',
56→              borderRadius: '0',
57→              height: 48,
58→              fontWeight: 500,
59→            }}
60→          />
61→          <button
62→            type="button"
63→            disabled={!canSearchPlate}
64→            onClick={() => canSearchPlate && alert(`Buscar por matrícula: ${plate}`)}
65→            onMouseEnter={() => setCtaHover(true)}
66→            onMouseLeave={() => setCtaHover(false)}
67→            className="text-white font-semibold text-[13px] tracking-wide transition-colors"
68→            style={{
69→              fontFamily: 'Montserrat, Arial, sans-serif',
70→              backgroundColor: canSearchPlate ? ctaBg : '#9C9C9C',
71→              borderRadius: '0 1.86px 1.86px 0',
72→              padding: '0 24px',
73→              height: 48,
74→              cursor: canSearchPlate ? 'pointer' : 'not-allowed',
75→            }}
76→          >
77→            Buscar
78→          </button>
79→        </div>
80→      </div>
81→
82→      {/* 3-step cascade */}
83→      <div className="mb-4">
84→        <div className="text-[14px] text-body-text mb-3 leading-snug">
85→          Seleccione su modelo de coche para buscar recambios de coches
86→        </div>
87→        <div className="space-y-2">
88→          <StepDropdown
89→            index={1}
90→            label="Elija una marca"
91→            value={selection.make}
92→            options={makeOptions}
93→            onSelect={setMake}
94→          />
95→          <StepDropdown
96→            index={2}
97→            label="Elija un modelo"
98→            value={selection.model}
99→            options={modelOptions}
100→            disabled={!selection.make}
101→            onSelect={setModel}
102→          />
103→          <StepDropdown
104→            index={3}
105→            label="Elija un tipo de motor"
106→            value={selection.engine}
107→            options={engineOptions}
108→            disabled={!selection.model}
109→            onSelect={setEngine}
110→          />
111→        </div>
112→      </div>
113→
114→      {/* Bottom Buscar (ALWAYS bright blue; hover -> lighter blue) */}
115→      <button
116→        type="button"
117→        disabled={!canSearch}
118→        onClick={() => canSearch && alert(`Buscar: ${selection.make} / ${selection.model} / ${selection.engine}`)}
119→        onMouseEnter={() => setCtaHover(true)}
120→        onMouseLeave={() => setCtaHover(false)}
121→        className="w-full text-white font-semibold text-[13px] tracking-wide transition-colors"
122→        style={{
123→          fontFamily: 'Montserrat, Arial, sans-serif',
124→          backgroundColor: ctaBg,
125→          borderRadius: '1.86px',
126→          padding: '0 24px',
127→          height: 48,
128→          opacity: 1, // NEVER visually disabled at first paint
129→          cursor: canSearch ? 'pointer' : 'not-allowed',
130→        }}
131→      >
132→        Buscar
133→      </button>
134→
135→      {/* Footer link */}
136→      <div className="mt-4 text-center">
137→        <a href="#" className="text-[12px] hover:underline" style={{ color: '#0068D7' }}>
138→          ¿SU COCHE NO SE ENCUENTRA PRESENTE EN EL CATALÓGO?
139→        </a>
140→      </div>
141→
142→      {selection.make && (
143→        <button onClick={reset} className="mt-3 text-[12px] text-gray-muted hover:underline">
144→          Restablecer selección
145→        </button>
146→      )}
147→    </div>
148→  );
149→}<END_OF_CONTENT>
